"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[62],{94497(n,e,r){r.r(e),r.d(e,{assets:()=>i,contentTitle:()=>o,default:()=>u,frontMatter:()=>l,metadata:()=>t,toc:()=>c});const t=JSON.parse('{"id":"cpp14/variable-templates","title":"\u53d8\u91cf\u6a21\u677f","description":"C++14 \u53d8\u91cf\u6a21\u677f \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp14/03-variable-templates.md","sourceDirName":"cpp14","slug":"/cpp14/03-variable-templates","permalink":"/LearnModernCpp/docs/cpp14/03-variable-templates","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp14","permalink":"/LearnModernCpp/docs/tags/cpp-14"},{"inline":true,"label":"variable_templates","permalink":"/LearnModernCpp/docs/tags/variable-templates"}],"version":"current","sidebarPosition":4,"frontMatter":{"sidebar_position":4,"slug":"03-variable-templates","title":"\u53d8\u91cf\u6a21\u677f","description":"C++14 \u53d8\u91cf\u6a21\u677f \u6559\u5b66\u793a\u4f8b","tags":["cpp14","variable_templates"]},"sidebar":"docs","previous":{"title":"\u51fd\u6570\u8fd4\u56de\u7c7b\u578b\u63a8\u5bfc","permalink":"/LearnModernCpp/docs/cpp14/02-return-type-deduction"},"next":{"title":"\u4e8c\u8fdb\u5236\u5b57\u9762\u91cf\u4e0e\u6570\u5b57\u5206\u9694\u7b26","permalink":"/LearnModernCpp/docs/cpp14/04-binary-literals-separators"}}');var a=r(74848),s=r(28453);const l={sidebar_position:4,slug:"03-variable-templates",title:"\u53d8\u91cf\u6a21\u677f",description:"C++14 \u53d8\u91cf\u6a21\u677f \u6559\u5b66\u793a\u4f8b",tags:["cpp14","variable_templates"]},o="\u53d8\u91cf\u6a21\u677f",i={},c=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function p(n){const e={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,s.R)(),...n.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(e.header,{children:(0,a.jsx)(e.h1,{id:"\u53d8\u91cf\u6a21\u677f",children:"\u53d8\u91cf\u6a21\u677f"})}),"\n",(0,a.jsx)(e.p,{children:"C++14 \u6807\u51c6\u5f15\u5165\u7684 \u53d8\u91cf\u6a21\u677f \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,a.jsx)(e.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,a.jsx)(e.pre,{children:(0,a.jsx)(e.code,{className:"language-cpp",metastring:'title="cpp14/03_variable_templates.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: \u53d8\u91cf\u6a21\u677f\r\n * \u6240\u5c5e\u6807\u51c6: C++14\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: C++14\u5141\u8bb8\u4f7f\u7528template\u5173\u952e\u5b57\u58f0\u660e\u53d8\u91cf\u6a21\u677f\uff0c\u4f7f\u53d8\u91cf\u672c\u8eab\u53ef\u4ee5\u53c2\u6570\u5316\u3002\r\n *          \u8fd9\u662f\u5bf9\u51fd\u6570\u6a21\u677f\u548c\u7c7b\u6a21\u677f\u7684\u81ea\u7136\u6269\u5c55\u2014\u2014\u73b0\u5728\u53d8\u91cf\u4e5f\u53ef\u4ee5\u6709\u6a21\u677f\u53c2\u6570\u3002\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: \u5728C++11\u4e2d\uff0c\u8981\u5b9e\u73b0\u53c2\u6570\u5316\u5e38\u91cf\u9700\u8981\u501f\u52a9constexpr\u51fd\u6570\u6216\u7c7b\u7684\u9759\u6001\r\n *              \u6210\u5458\uff0c\u8bed\u6cd5\u7e41\u7410\u3002\u53d8\u91cf\u6a21\u677f\u76f4\u63a5\u652f\u6301"\u53c2\u6570\u5316\u53d8\u91cf"\u7684\u8bed\u4e49\uff0c\u4f7fpi<double>\r\n *              \u8fd9\u6837\u7684\u5199\u6cd5\u6210\u4e3a\u53ef\u80fd\u3002\u6807\u51c6\u5e93\u4e2d\u7684_v\u540e\u7f00\u7c7b\u578b\u7279\u5f81\u5c31\u662f\u53d8\u91cf\u6a21\u677f\u7684\u5e94\u7528\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - \u53d8\u91cf\u6a21\u677f\u53ef\u4ee5\u6709\u9ed8\u8ba4\u6a21\u677f\u53c2\u6570\r\n *   - \u53ef\u4ee5\u5bf9\u53d8\u91cf\u6a21\u677f\u8fdb\u884c\u7279\u5316\uff08\u5168\u7279\u5316\u548c\u504f\u7279\u5316\uff09\r\n *   - \u5e38\u4e0econstexpr\u7ed3\u5408\u7528\u4e8e\u7f16\u8bd1\u671f\u5e38\u91cf\r\n *   - \u6807\u51c6\u5e93\u4e2dis_same_v<T,U>\u7b49_v\u540e\u7f00\u5c31\u662f\u53d8\u91cf\u6a21\u677f\u7684\u5178\u578b\u5e94\u7528\r\n * ============================================================\r\n */\r\n\r\n#include <iostream>\r\n#include <string>\r\n#include <type_traits>\r\n#include <cmath>\r\n\r\n// ============================================================\r\n// \u57fa\u7840\u7528\u6cd5\r\n// ============================================================\r\n\r\n// 1. \u6700\u7ecf\u5178\u7684\u53d8\u91cf\u6a21\u677f\uff1a\u6570\u5b66\u5e38\u91cfpi\r\ntemplate<typename T>\r\nconstexpr T pi = T(3.14159265358979323846L);\r\n\r\n// 2. \u53e6\u4e00\u4e2a\u6570\u5b66\u5e38\u91cf\r\ntemplate<typename T>\r\nconstexpr T e = T(2.71828182845904523536L);\r\n\r\n// 3. \u7b80\u5355\u7684\u53d8\u91cf\u6a21\u677f\uff08\u975econstexpr\u4e5f\u884c\uff0c\u4f46\u5e38\u91cf\u573a\u666f\u6700\u5e38\u7528\uff09\r\ntemplate<typename T>\r\nT default_value = T{};  // \u5404\u7c7b\u578b\u7684\u9ed8\u8ba4\u503c\r\n\r\nvoid basic_usage() {\r\n    std::cout << "--- basic_usage ---\\n";\r\n\r\n    // \u4e0d\u540c\u7cbe\u5ea6\u7684pi\r\n    std::cout << "  pi<float>       = " << pi<float> << "\\n";\r\n    std::cout << "  pi<double>      = " << pi<double> << "\\n";\r\n    std::cout << "  pi<long double> = " << pi<long double> << "\\n";\r\n\r\n    // \u5229\u7528pi\u8fdb\u884c\u8ba1\u7b97\r\n    double radius = 5.0;\r\n    double area = pi<double> * radius * radius;\r\n    std::cout << "  \u5706\u9762\u79ef(r=5): " << area << "\\n";\r\n\r\n    // e\u5e38\u91cf\r\n    std::cout << "  e<double>       = " << e<double> << "\\n";\r\n\r\n    // \u9ed8\u8ba4\u503c\r\n    std::cout << "  default_value<int>    = " << default_value<int> << "\\n";\r\n    std::cout << "  default_value<double> = " << default_value<double> << "\\n";\r\n    std::cout << "  default_value<string> = \\"" << default_value<std::string> << "\\"\\n";\r\n}\r\n\r\n// ============================================================\r\n// \u8fdb\u9636\u7528\u6cd5\r\n// ============================================================\r\n\r\n// 1. \u4e0econstexpr\u51fd\u6570\u7684\u5bf9\u6bd4\r\n// C++11\u65b9\u5f0f\uff1a\u7528constexpr\u51fd\u6570\u5305\u88c5\r\ntemplate<typename T>\r\nconstexpr T pi_func() { return T(3.14159265358979323846L); }\r\n\r\n// C++14\u65b9\u5f0f\uff1a\u53d8\u91cf\u6a21\u677f\u2014\u2014\u66f4\u76f4\u89c2\r\n// \uff08pi<T>\u5df2\u5728\u4e0a\u9762\u5b9a\u4e49\uff09\r\n\r\n// 2. \u53d8\u91cf\u6a21\u677f\u7684\u7279\u5316\r\ntemplate<typename T>\r\nconstexpr T max_value = T{};   // \u9ed8\u8ba4\r\n\r\ntemplate<>\r\nconstexpr int max_value<int> = 2147483647;\r\n\r\ntemplate<>\r\nconstexpr double max_value<double> = 1.7976931348623157e+308;\r\n\r\ntemplate<>\r\nconstexpr char max_value<char> = 127;\r\n\r\n// 3. \u6a21\u62df\u6807\u51c6\u5e93\u7684_v\u540e\u7f00\u7c7b\u578b\u7279\u5f81\r\n// \u6807\u51c6\u5e93\u76f4\u5230C++17\u624d\u6b63\u5f0f\u63d0\u4f9b is_same_v \u7b49\uff0c\u4f46C++14\u53d8\u91cf\u6a21\u677f\u53ef\u4ee5\u81ea\u884c\u5b9e\u73b0\r\ntemplate<typename T, typename U>\r\nconstexpr bool is_same_v = std::is_same<T, U>::value;\r\n\r\ntemplate<typename T>\r\nconstexpr bool is_integral_v = std::is_integral<T>::value;\r\n\r\ntemplate<typename T>\r\nconstexpr bool is_floating_point_v = std::is_floating_point<T>::value;\r\n\r\n// 4. \u5e26\u9ed8\u8ba4\u6a21\u677f\u53c2\u6570\u7684\u53d8\u91cf\u6a21\u677f\r\ntemplate<typename T = double>\r\nconstexpr T golden_ratio = T(1.6180339887498948482L);\r\n\r\n// 5. \u7528\u53d8\u91cf\u6a21\u677f\u7b80\u5316\u6a21\u677f\u5143\u7f16\u7a0b\r\ntemplate<unsigned N>\r\nconstexpr unsigned factorial_v = N * factorial_v<N - 1>;\r\n\r\ntemplate<>\r\nconstexpr unsigned factorial_v<0> = 1;\r\n\r\nvoid advanced_usage() {\r\n    std::cout << "\\n--- advanced_usage ---\\n";\r\n\r\n    // 1. \u5bf9\u6bd4\uff1a\u51fd\u6570\u8c03\u7528 vs \u53d8\u91cf\u6a21\u677f\r\n    std::cout << "  constexpr\u51fd\u6570: pi_func<double>() = " << pi_func<double>() << "\\n";\r\n    std::cout << "  \u53d8\u91cf\u6a21\u677f:      pi<double>         = " << pi<double> << "\\n";\r\n    std::cout << "  \u53d8\u91cf\u6a21\u677f\u8bed\u6cd5\u66f4\u7b80\u6d01\u81ea\u7136\\n";\r\n\r\n    // 2. \u7279\u5316\r\n    std::cout << "  max_value<int>    = " << max_value<int> << "\\n";\r\n    std::cout << "  max_value<double> = " << max_value<double> << "\\n";\r\n    std::cout << "  max_value<char>   = " << (int)max_value<char> << "\\n";\r\n\r\n    // 3. \u7c7b\u578b\u7279\u5f81_v\u7b80\u5316\r\n    std::cout << "  is_same_v<int, int>         = " << is_same_v<int, int> << "\\n";\r\n    std::cout << "  is_same_v<int, double>      = " << is_same_v<int, double> << "\\n";\r\n    std::cout << "  is_integral_v<int>          = " << is_integral_v<int> << "\\n";\r\n    std::cout << "  is_floating_point_v<double> = " << is_floating_point_v<double> << "\\n";\r\n\r\n    // \u5bf9\u6bd4C++11\u7684\u5199\u6cd5\r\n    std::cout << "  C++11: std::is_same<int,int>::value = "\r\n              << std::is_same<int, int>::value << "\\n";\r\n    std::cout << "  C++14: is_same_v<int,int>           = "\r\n              << is_same_v<int, int> << " (\u66f4\u7b80\u6d01!)\\n";\r\n\r\n    // 4. \u9ed8\u8ba4\u6a21\u677f\u53c2\u6570\r\n    std::cout << "  golden_ratio<>       = " << golden_ratio<> << "\\n";\r\n    std::cout << "  golden_ratio<float>  = " << golden_ratio<float> << "\\n";\r\n\r\n    // 5. \u7f16\u8bd1\u671f\u9636\u4e58\r\n    std::cout << "  factorial_v<0>  = " << factorial_v<0> << "\\n";\r\n    std::cout << "  factorial_v<5>  = " << factorial_v<5> << "\\n";\r\n    std::cout << "  factorial_v<10> = " << factorial_v<10> << "\\n";\r\n\r\n    // \u7f16\u8bd1\u671f\u9a8c\u8bc1\r\n    static_assert(factorial_v<5> == 120, "5! should be 120");\r\n    static_assert(factorial_v<0> == 1, "0! should be 1");\r\n}\r\n\r\n// ============================================================\r\n// \u6613\u9519\u70b9\u4e0e\u9677\u9631\r\n// ============================================================\r\n\r\n// \u7528\u4e8e\u6f14\u793a\u9677\u9631\u7684\u53d8\u91cf\u6a21\u677f\r\ntemplate<typename T>\r\nT mutable_var = T(42);  // \u975econst\uff01\u6bcf\u4e2a\u7ffb\u8bd1\u5355\u5143\u72ec\u7acb\r\n\r\nvoid pitfalls() {\r\n    std::cout << "\\n--- pitfalls ---\\n";\r\n\r\n    // \u9677\u96311\uff1a\u975econst\u53d8\u91cf\u6a21\u677f\u7684\u6bcf\u4e2a\u5b9e\u4f8b\u5316\u662f\u72ec\u7acb\u7684\u53d8\u91cf\r\n    std::cout << "  \u9677\u96311: \u975econst\u53d8\u91cf\u6a21\u677f\u7684\u5b9e\u4f8b\u662f\u72ec\u7acb\u53d8\u91cf\\n";\r\n    mutable_var<int> = 100;\r\n    mutable_var<double> = 200.0;\r\n    std::cout << "    mutable_var<int>    = " << mutable_var<int> << "\\n";\r\n    std::cout << "    mutable_var<double> = " << mutable_var<double> << "\\n";\r\n    // \u4fee\u6539int\u7248\u672c\u4e0d\u5f71\u54cddouble\u7248\u672c\uff0c\u5b83\u4eec\u662f\u5b8c\u5168\u72ec\u7acb\u7684\u53d8\u91cf\r\n\r\n    // \u9677\u96312\uff1a\u53d8\u91cf\u6a21\u677f\u4e0d\u662f\u7c7b\u578b\uff0c\u4e0d\u80fd\u7528\u4e8e\u7c7b\u578b\u53c2\u6570\r\n    std::cout << "  \u9677\u96312: \u53d8\u91cf\u6a21\u677f\u662f\u503c\uff0c\u4e0d\u662f\u7c7b\u578b\\n";\r\n    std::cout << "    pi<double>\u7684\u7c7b\u578b\u662f: const double\\n";\r\n    // template<typename T> constexpr T pi \u7684\u6bcf\u4e2a\u5b9e\u4f8b\u5316\u90fd\u662f\u4e00\u4e2a\u72ec\u7acb\u7684\u53d8\u91cf\r\n\r\n    // \u9677\u96313\uff1aODR\uff08\u5355\u4e00\u5b9a\u4e49\u89c4\u5219\uff09\u6ce8\u610f\u4e8b\u9879\r\n    std::cout << "  \u9677\u96313: \u975e\u5185\u8054\u975econstexpr\u53d8\u91cf\u6a21\u677f\u5728\u591a\u4e2a\u7ffb\u8bd1\u5355\u5143\u4e2d\u53ef\u80fd\u6709\u591a\u4e2a\u526f\u672c\\n";\r\n    std::cout << "    \u5efa\u8bae\uff1a\u53d8\u91cf\u6a21\u677f\u5c3d\u91cf\u4f7f\u7528constexpr\uff0c\u786e\u4fdd\u7f16\u8bd1\u671f\u5e38\u91cf\u8bed\u4e49\\n";\r\n\r\n    // \u9677\u96314\uff1a\u53d8\u91cf\u6a21\u677f\u7684\u7279\u5316\u5fc5\u987b\u5728\u4f7f\u7528\u4e4b\u524d\u58f0\u660e\r\n    std::cout << "  \u9677\u96314: \u7279\u5316\u5fc5\u987b\u5728\u9996\u6b21\u4f7f\u7528\u4e4b\u524d\u53ef\u89c1\uff0c\u5426\u5219\u4f7f\u7528\u901a\u7528\u7248\u672c\\n";\r\n\r\n    // \u9677\u96315\uff1a\u4e0d\u8981\u5728\u5934\u6587\u4ef6\u4e2d\u58f0\u660e\u975econst\u7684\u53d8\u91cf\u6a21\u677f\r\n    std::cout << "  \u9677\u96315: \u5934\u6587\u4ef6\u4e2d\u7684\u975econst\u53d8\u91cf\u6a21\u677f\u53ef\u80fd\u5bfc\u81f4\u94fe\u63a5\u95ee\u9898\\n";\r\n    std::cout << "    \u5efa\u8bae\uff1a\u5934\u6587\u4ef6\u4e2d\u53ea\u4f7f\u7528constexpr\u53d8\u91cf\u6a21\u677f\\n";\r\n}\r\n\r\n// ============================================================\r\n// \u4e3b\u51fd\u6570\r\n// ============================================================\r\nint main() {\r\n    std::cout << "===== \u53d8\u91cf\u6a21\u677f - C++14 =====\\n\\n";\r\n\r\n    basic_usage();\r\n    advanced_usage();\r\n    pitfalls();\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,a.jsx)(e.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,a.jsxs)(e.ul,{children:["\n",(0,a.jsx)(e.li,{children:(0,a.jsx)(e.a,{href:"https://en.cppreference.com/w/cpp/language/variable_template",children:"cppreference: \u53d8\u91cf\u6a21\u677f"})}),"\n"]})]})}function u(n={}){const{wrapper:e}={...(0,s.R)(),...n.components};return e?(0,a.jsx)(e,{...n,children:(0,a.jsx)(p,{...n})}):p(n)}},28453(n,e,r){r.d(e,{R:()=>l,x:()=>o});var t=r(96540);const a={},s=t.createContext(a);function l(n){const e=t.useContext(s);return t.useMemo(function(){return"function"==typeof n?n(e):{...e,...n}},[e,n])}function o(n){let e;return e=n.disableParentContext?"function"==typeof n.components?n.components(a):n.components||a:l(n.components),t.createElement(s.Provider,{value:e},n.children)}}}]);